-- Source of truth for factor metric display definitions.
-- Reapply this file to refresh metric-level display metadata.

DROP TABLE IF EXISTS public.ticker_factor_metric_display_definitions;

CREATE TABLE public.ticker_factor_metric_display_definitions (
  id BIGSERIAL PRIMARY KEY,

  model_key TEXT NOT NULL,
  model_version TEXT NOT NULL,

  factor TEXT NOT NULL,
  axis TEXT NOT NULL,
  metric_key TEXT NOT NULL,

  metric_label TEXT,
  metric_description TEXT,
  chart_payload JSONB NOT NULL DEFAULT '{}'::jsonb,
  display_payload JSONB NOT NULL DEFAULT '{}'::jsonb,

  display_order INTEGER NOT NULL DEFAULT 100,
  is_active BOOLEAN NOT NULL DEFAULT true,

  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now(),

  CONSTRAINT uq_tfmdd UNIQUE (
    model_key,
    model_version,
    factor,
    axis,
    metric_key
  ),

  CONSTRAINT chk_tfmdd_chart_payload_object
  CHECK (jsonb_typeof(chart_payload) = 'object'),

  CONSTRAINT chk_tfmdd_display_payload_object
  CHECK (jsonb_typeof(display_payload) = 'object')
);

CREATE INDEX idx_tfmdd_active_lookup
ON public.ticker_factor_metric_display_definitions (
  factor,
  axis,
  metric_key,
  is_active
);

